import{_ as i,o as t,c as a,ag as s}from"./chunks/framework.B9unkguw.js";const g=JSON.parse('{"title":"Generated Vehicle Config Pages","description":"","frontmatter":{},"headers":[],"relativePath":"ko/qgc-dev-guide/views/vehicle_config_generation.md","filePath":"ko/qgc-dev-guide/views/vehicle_config_generation.md"}'),n={name:"ko/qgc-dev-guide/views/vehicle_config_generation.md"};function o(l,e,r,d,c,h){return t(),a("div",null,e[0]||(e[0]=[s(`<h1 id="generated-vehicle-config-pages" tabindex="-1">Generated Vehicle Config Pages <a class="header-anchor" href="#generated-vehicle-config-pages" aria-label="Permalink to &quot;Generated Vehicle Config Pages&quot;">​</a></h1><p>This page explains how the Vehicle Setup pages (Power, Safety, etc.) are generated from JSON definitions and how to extend them.</p><p>For the complete JSON schema reference see <a href="./../../../../tools/generators/config_qml/README.html">tools/generators/config_qml/README.md</a>.</p><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The generation pipeline is:</p><ol><li><strong>JSON page definitions</strong> in <code>src/AutoPilotPlugins/{APM,PX4}/VehicleConfig/*.VehicleConfig.json</code></li><li><strong>Python generator</strong> in <code>tools/generators/config_qml/page_generator.py</code></li><li><strong>Generated QML</strong> in <code>build/src/AutoPilotPlugins/{APM,PX4}/generated/</code></li><li><strong>C++ component class</strong> (e.g. <code>APMPowerComponent</code>) loads the generated QML via <code>setupSource()</code></li></ol><p>At build time, CMake runs the generator for each firmware plugin and places generated QML files in the build tree. Those files are compiled into the corresponding <code>QGroundControl.AutoPilotPlugins.*</code> QML module.</p><h2 id="where-generation-is-wired" tabindex="-1">Where Generation Is Wired <a class="header-anchor" href="#where-generation-is-wired" aria-label="Permalink to &quot;Where Generation Is Wired&quot;">​</a></h2><p>Generation is configured in each firmware plugin&#39;s <code>CMakeLists.txt</code>:</p><ul><li><code>src/AutoPilotPlugins/APM/CMakeLists.txt</code> — target <code>GenerateConfigQmlAPM</code></li><li><code>src/AutoPilotPlugins/PX4/CMakeLists.txt</code> — target <code>GenerateConfigQmlPX4</code></li></ul><p>Each runs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tools.generators.config_qml.generate_pages</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --pages-dir</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pages_di</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --output-dir</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">build_gen_di</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>The generator entry point is <code>tools/generators/config_qml/generate_pages.py</code>, with most logic in <code>tools/generators/config_qml/page_generator.py</code>.</p><h2 id="base-class-vehiclecomponent" tabindex="-1">Base Class: VehicleComponent <a class="header-anchor" href="#base-class-vehiclecomponent" aria-label="Permalink to &quot;Base Class: VehicleComponent&quot;">​</a></h2><p><code>VehicleComponent</code> (in <code>src/AutoPilotPlugins/VehicleComponent.h</code>) provides the C++ side for generated pages. It reads the same JSON file at runtime to:</p><ul><li>Build the <strong>sidebar section list</strong> (including expanded repeat sections)</li><li><strong>Dynamically filter</strong> disabled repeat instances from the sidebar</li><li><strong>Connect signals</strong> so the sidebar updates when enable parameters change</li></ul><p>Subclasses only need to implement <code>vehicleConfigJson()</code> to return the path to the JSON file and <code>setupSource()</code> to return the generated QML URL.</p><h2 id="adding-a-new-generated-setup-page" tabindex="-1">Adding a New Generated Setup Page <a class="header-anchor" href="#adding-a-new-generated-setup-page" aria-label="Permalink to &quot;Adding a New Generated Setup Page&quot;">​</a></h2><ol><li><p>Create a new JSON file in the appropriate <code>VehicleConfig/</code> directory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/AutoPilotPlugins/APM/VehicleConfig/MyFeature.VehicleConfig.json</span></span></code></pre></div><p>See <a href="./../../../../tools/generators/config_qml/README.html">tools/generators/config_qml/README.md</a> for the full JSON schema.</p></li><li><p>Create a minimal C++ component class inheriting <code>VehicleComponent</code>:</p><ul><li>Implement <code>vehicleConfigJson()</code> to return the JSON path</li><li>Implement <code>setupSource()</code> to return the generated QML URL</li></ul></li><li><p>Register the component in the firmware plugin&#39;s <code>AutoPilotPlugin</code> subclass.</p></li><li><p>Add the generated QML filename to <code>_config_generated_qml_names</code> in the plugin&#39;s <code>CMakeLists.txt</code>.</p></li><li><p>Build. CMake will regenerate the QML automatically:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Debug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GenerateConfigQmlAPM</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # or GenerateConfigQmlPX4</span></span></code></pre></div></li></ol><h2 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h2><ul><li>The <code>constants</code>, <code>params</code>, and <code>bindings</code> sections should appear <strong>before</strong> <code>sections</code> in the JSON file for readability, since sections reference them.</li><li>Constants should use native JSON numbers, not strings (e.g. <code>0</code> not <code>&quot;0&quot;</code>).</li><li>The <code>_config_generated_qml_names</code> list in CMake is explicit. If you forget to add a new page output file, integration will be incomplete.</li><li>Inside repeat sections, use parameter <strong>postfixes</strong> in <code>param</code> fields and <code>_fullParamName()</code> in <code>showWhen</code> expressions.</li><li>The <code>enableParam</code>/<code>disabledParamValue</code> pair is required together — you cannot specify one without the other.</li></ul>`,21)]))}const u=i(n,[["render",o]]);export{g as __pageData,u as default};
